def countOfAtoms(self, formula: str) -> str:
    result = []
    stack = []
    for char in formula:
        if char == '(':
            stack.append(char)
        elif char == ')':
            while stack and stack[-1] != '(':
                stack.pop()
        else:
            element = {}
            while stack and stack[-1] != '(':
                element[stack.pop()] = 1
            while stack:
                element[stack.pop()] += 1
            result.append(element)
    return ''.join(sorted(result))

